head.script:
scwin.strCurDate = $c.date.getServerDateTime("yyyyMMdd")
scwin.strPreDate = $c.date.addDate(scwin.strCurDate, -2)

scwin.userId = $c.data.getMemInfo("userId")
scwin.loginClntNo = $c.data.getMemInfo("clntNo") == null ? "" : $c.data.getMemInfo("clntNo")
scwin.loginClntNm = $c.data.getMemInfo("clntNm") //거래처명
scwin.userClsCd = $c.data.getMemInfo("userClsCd")	// 사용자 구분코드

scwin.hd_kcomcd = "DBEX" // 대표거래처 코드

//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.onpageload = function () {


};

//-------------------------------------------------------------------------
// 화면로딩시 UDC 호출
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function () {
    rd_cnd_rd_prtOpt1.setValue("");
    ed_cnd_ed_hhetaFrom.setValue(scwin.strPreDate);
    ed_cnd_ed_hhetaTo.setValue(scwin.strCurDate);
};

//-------------------------------------------------------------------------
// print
//-------------------------------------------------------------------------		
scwin.f_Print = async function (e) {

    if (ed_cnd_ed_hhetaFrom.getValue() == "") {
        await $c.win.alert($c.data.getMessage(E_MSG_CM_ERR_002, "DO Date From")); //@는 필수입력항목입니다.				
        ed_cnd_ed_hhetaFrom.focus();
        return false;
    }

    if (ed_cnd_ed_hhetaTo.getValue() == "") {
        await $c.win.alert($c.data.getMessage(E_MSG_CM_ERR_002, "DO Date To"));//@는 필수입력항목입니다.			
        ed_cnd_ed_hhetaTo.focus();
        return false;
    }

    let data = {
        odiName: 'se_207_01_01',
        reportName: '/il/seainb/se_207_01_01.ozr',
        odiParam: {
            KCOMCD: scwin.hd_kcomcd
            , PRT_TYPE: rd_cnd_rd_prtOpt1.getValue()
            , FROM_DATE: ed_cnd_ed_hhetaFrom.getValue()
            , TO_DATE: ed_cnd_ed_hhetaTo.getValue()
            , USERID: scwin.userId
        },
        viewerParam: {  // OZ 뷰어에 대한 설정
            useprogressbar: false,
            zoom: 100,
            mode: 'print'
        },
        formParam: {   // 리포트(OZR)에 적용할 파라미터를 설정(OZFormParam)
        }
    };

    scwin.openOzPopup(data);
};


/**
 * @method
 * @name openOzPopup
 * @description 오즈리포트 화면을 띄운다
 * @param {string} data desc
 * @hidden N
 * @exception 
 * @example ${example}
 */
scwin.openOzPopup = async function (data) {
    let opts = {
        id: "ozReportPopup",
        popupName: "오즈 리포트",
        modal: true,
        type: "browserPopup",
        width: 1000,
        height: 600,
        title: "오즈 리포트"
    };
    await $c.win.openPopup("/ui/cm/zz/ozreportPopup.xml", opts, data);
};
